test_local.py :: step
def step(label: str):
    print(f"\n{colors.BOLD}▶ {label}{colors.END}")

test_local.py :: check
def check(label: str, response, expect_status: int = 200):
    global passed, failed
    ok = response.status_code == expect_status
    data = None
    try:
        data = response.json()
    except Exception:
        pass

    if ok:
        passed += 1
        tag = f"{colors.OK}✓ PASS{colors.END}"
    else:
        failed += 1
        tag = f"{colors.FAIL}✗ FAIL{colors.END}"

    print(f"  {tag}  {label}  [{response.status_code}]")
    if not ok:
        print(f"       expected {expect_status}, body: {json.dumps(data, indent=2, default=str)[:300]}")
    return data

test_local.py :: auth_header
def auth_header(token: str) -> dict:
    return {"Authorization": f"Bearer {token}"}
